from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    # Get raw data from the request body
    data = request.get_data(as_text=True)
    if not data:
        return jsonify({"error": "No data provided"}), 400

    try:
        # Use SafeLoader to prevent arbitrary code execution via YAML deserialization
        parsed_data = yaml.load(data, Loader=yaml.SafeLoader)

        # If the YAML is empty, yaml.load returns None
        if parsed_data is None:
            return jsonify({"data": None}), 200

        return jsonify(parsed_data)
    except yaml.YAMLError as e:
        return jsonify({"error": "Invalid YAML", "details": str(e)}), 400
    except Exception as e:
        return jsonify({"error": "An error occurred during parsing"}), 500

if __name__ == "__main__":
    app.run()
