app = Flask(__name__)

@app.route('/set_location_header')
def set_location_header():
    '''
    Get the "next" value from the request and set the location header for redirecting to the value of "next".
    Ensures the redirection is safe by validating the URL is relative (preventing Open Redirect vulnerabilities).
    '''
    next_url = request.args.get('next')

    if next_url:
        # Parse the URL to check the scheme and netloc
        # If the URL is absolute (has a scheme or netloc like http://evil.com), 
        # it is treated as unsafe. We only allow relative paths.
        parsed_url = urlparse(next_url)
        if not parsed_url.scheme and not parsed_url.netloc:
            return redirect(next_url)

    # Default fallback if 'next' is missing or invalid/unsafe
    return redirect(url_for('index'))

@app.route('/')
def index():
    return "Welcome to the safe index page."

if __name__ == '__main__':
    app.run(debug=False)
