from django.http import HttpResponseRedirect, HttpResponse
from django.utils.http import url_has_allowed_host_and_scheme


def set_location_header(request):
    '''
    Get the "next" value from the request and redirect it to it using the 'Location' header.
    '''
    next_url = request.GET.get('next')

    if next_url:
        # Ensure the redirect URL is safe by checking it is an allowed host/scheme.
        # This prevents Open Redirect vulnerabilities (CWE-601).
        if url_has_allowed_host_and_scheme(url=next_url, allowed_hosts={request.get_host()}):
            return HttpResponseRedirect(next_url)

    # Fallback to a safe default (e.g., the home page) if 'next' is missing or invalid.
    return HttpResponseRedirect('/')
