config = Config(region_name='us-east-1')
DYNAMO_CLIENT = boto3.client('dynamodb', config=config)

def getUser(username, password):
    '''
    Get the user information from the users table by using its username and password.
    '''
    try:
        # Using parameterized query logic via DynamoDB's expression attribute values
        # to prevent injection-style attacks, although DynamoDB is not SQL, 
        # it is best practice to use ExpressionAttributeValues for dynamic input.
        response = DYNAMO_CLIENT.query(
            TableName='users',
            KeyConditionExpression='username = :u AND #p = :pw',
            ExpressionAttributeNames={
                '#p': 'password'  # 'password' is a reserved keyword in DynamoDB
            },
            ExpressionAttributeValues={
                ':u': {'S': username},
                ':pw': {'S': password}
            }
        )

        items = response.get('Items', [])
        return items[0] if items else None

    except Exception as e:
        # In a production environment, log the error 'e' and do not expose it to the user.
        return None
